var $bm_rt;
var freq, jumpH, t, bounce;
freq = 0.9;
jumpH = 8;
t = $bm_mod($bm_mul(time, freq), 1);
bounce = t < 0.5 ? $bm_mul($bm_neg(Math.sin($bm_mul(t, Math.PI))), jumpH) : 0;
$bm_rt = [
    value[0],
    value[1] + bounce
];

s.x:
var $bm_rt;
var freq, amp, s;
freq = 0.8;
amp = 0.025;
s = $bm_sum(1, $bm_mul(Math.sin($bm_mul($bm_mul($bm_mul(time, freq), Math.PI), 2)), amp));
$bm_rt = [
    value[0] * s,
    value[1] * s
];
